import{_ as e,o as a,c as s,a2 as i}from"./chunks/framework.DTa47_fH.js";const u=JSON.parse('{"title":"Application Assessment","description":"","frontmatter":{},"headers":[],"relativePath":"assessment/application.md","filePath":"assessment/application.md"}'),n={name:"assessment/application.md"};function r(o,t,d,c,l,p){return a(),s("div",null,[...t[0]||(t[0]=[i(`<h1 id="application-assessment" tabindex="-1">Application Assessment <a class="header-anchor" href="#application-assessment" aria-label="Permalink to &quot;Application Assessment&quot;">​</a></h1><p>Application Assessment is SWAO&#39;s core capability. It analyses a cloud application from its source code, configuration files, and operational context documents, then produces a comprehensive set of compliance signals, a migration readiness verdict, and a full publication package.</p><p><strong>CLI:</strong> <code>swao assess --app &lt;app-id&gt;</code></p><p><strong>TUI:</strong> Main Menu &gt; Run Assessment &gt; [1] Application Assessment</p><hr><h2 id="what-it-produces" tabindex="-1">What it produces <a class="header-anchor" href="#what-it-produces" aria-label="Permalink to &quot;What it produces&quot;">​</a></h2><p>After a complete assessment run you receive:</p><table tabindex="0"><thead><tr><th>Output</th><th>Where to find it</th><th>What it contains</th></tr></thead><tbody><tr><td>Signals</td><td><code>apps/&lt;id&gt;/wsp/signals/</code></td><td>Every finding with ID, severity, control mapping, rationale, and evidence</td></tr><tr><td>Auditor report</td><td><code>apps/&lt;id&gt;/wsp/auditor.md</code></td><td>Full signal list in Markdown -- printable, emailable</td></tr><tr><td>BI export bundle</td><td><code>apps/&lt;id&gt;/wsp/exports/</code></td><td>17-table star schema (CSV + NDJSON + XLSX) for Power BI or Tableau</td></tr><tr><td>HTML publication</td><td><code>apps/&lt;id&gt;/wsp/publications/</code></td><td>Self-contained HTML file with search, persona views, and evidence gallery</td></tr></tbody></table><hr><h2 id="analysis-passes" tabindex="-1">Analysis passes <a class="header-anchor" href="#analysis-passes" aria-label="Permalink to &quot;Analysis passes&quot;">​</a></h2><p>SWAO runs up to 14 analysis passes, each targeting a specific aspect of the application. Passes that do not require an LLM are always included; LLM-dependent passes require a configured provider.</p><table tabindex="0"><thead><tr><th>Pass</th><th>What it analyses</th><th>LLM?</th></tr></thead><tbody><tr><td>Inventory</td><td>File types, tech stack, dependency manifest detection</td><td>No</td></tr><tr><td>State analysis</td><td>Runtime configuration, environment variables, secrets hygiene</td><td>No</td></tr><tr><td>Data classification</td><td>PII and sensitive data fields in schemas and source code</td><td>No</td></tr><tr><td>Context ingestion</td><td>Documents you place in <code>apps/&lt;id&gt;/ingestion/</code> (CMDB, architecture reviews, transcripts)</td><td>Yes</td></tr><tr><td>Compliance evaluation</td><td>Source code against active framework controls (GDPR, BSI C5, etc.)</td><td>Yes</td></tr><tr><td>SBOM</td><td>Software Bill of Materials from dependency manifests</td><td>No</td></tr><tr><td>Cryptography</td><td>Cipher suite usage, certificate management, key handling</td><td>No</td></tr><tr><td>7R synthesis</td><td>Migration strategy recommendation (Retire, Retain, Rehost, Replatform, Refactor, Re-architect, Replace)</td><td>Yes</td></tr><tr><td>Landing zone readiness</td><td>Sovereign cloud target compatibility check</td><td>No</td></tr><tr><td>Risk register</td><td>Derived risk entries from signal aggregation</td><td>No</td></tr></tbody></table><p>Passes that cannot run (missing source, missing credentials, LLM not configured) are skipped gracefully -- SWAO reports which passes ran and which were skipped at the end of each run.</p><hr><h2 id="compliance-frameworks" tabindex="-1">Compliance frameworks <a class="header-anchor" href="#compliance-frameworks" aria-label="Permalink to &quot;Compliance frameworks&quot;">​</a></h2><p>Assessment evaluates signals against whichever frameworks are active in your workspace. You can install and activate frameworks with:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>swao framework list</span></span>
<span class="line"><span>swao framework install &lt;id&gt;</span></span></code></pre></div><p>Nine community frameworks are available out of the box: GDPR, AI 10 Pillars, COBIT 5, NIST SP 800-66 R2, ISO 27001, PCI DSS, SOC 2, BSI C5, DORA. Custom frameworks (your own YAML) are also supported in all editions.</p><hr><h2 id="context-ingestion" tabindex="-1">Context ingestion <a class="header-anchor" href="#context-ingestion" aria-label="Permalink to &quot;Context ingestion&quot;">​</a></h2><p>Place supporting documents in <code>apps/&lt;app-id&gt;/ingestion/</code> before running assessment to give SWAO operational context that is not visible from source code alone:</p><ul><li>Architecture diagrams (PDF, DOCX, MD)</li><li>CMDB / ServiceNow exports (CSV, XLSX, JSON)</li><li>Workshop transcripts or interview notes (DOCX, MD, TXT)</li><li>Terraform or IaC state files</li><li>Existing audit findings or risk registers</li></ul><p>SWAO reads these during the Context Ingestion pass and fuses the findings with source-derived signals. Evidence extracted from context documents is attributed separately in the output so auditors can trace every finding to its source.</p><hr><h2 id="running-time" tabindex="-1">Running time <a class="header-anchor" href="#running-time" aria-label="Permalink to &quot;Running time&quot;">​</a></h2><p>A complete run against a medium-sized application (50 000 lines, 3 LLM passes) typically takes 3 to 8 minutes depending on the LLM provider&#39;s response time. Subsequent runs that use cached results for unchanged files are significantly faster.</p>`,26)])])}const m=e(n,[["render",r]]);export{u as __pageData,m as default};
